The following example demonstrates how to initialize and use the .

using System.ComponentModel;
using Syncfusion.Maui.ListView;
using Microsoft.Maui.Controls;


namespace BookInfo
{


  class BookInfo
  {


    public string BookName { get; set; }
    public string BookAuthor { get; set; }


    public BookInfo(string bookName, string bookAuthor)
    {
       BookName = bookName;
       BookAuthor = bookAuthor;
    }


}


  class BookInfoMainPage : ContentPage
  {


    public BookInfoMainPage()
    {


      // Define some data.
      List bookInfo = new List
      {
        new BookInfo("Xamarin.Forms", " by Derek Jensen "),
        new BookInfo("Object-Oriented Programming in C#", "by Sander Rossel"),
        new BookInfo("iOS Succinctly", "by Ryan Hodson"),
        new BookInfo("Android Programming", "by Ryan Hodson"),
      };


      // Initializes the SfListView
      SfListView listView = new SfListView
      {
        // Source of the data
        ItemsSource = bookInfo,


        // Define the template for displaying each item
        ItemTemplate = new DataTemplate(() =>
        {
          // Create a view with bindings for displaying each property.
          Label bookNameLabel = new Label() { FontSize = 18};
          bookNameLabel.SetBinding(Label.TextProperty, "BookName");


          Label bookAuthorLabel = new Label() { FontSize = 12 };
          bookAuthorLabel.SetBinding(Label.TextProperty, "BookAuthor");


          // returns a ViewCell.
          return new ViewCell
          {
            View = new StackLayout
            {
               Children =
               {
                 bookNameLabel,
                 bookAuthorLabel
               }
            }
          };
        })
      };


      this.Content = listView;
    }
  }
}

The following example demonstrates how to wire the  event in  and cancel the swiping action on specific item in the list.


 <syncfusion:SfListView x:Name="listView"
                        ItemsSource="{Binding contactsinfo}"
                        AllowSwiping="True"
                        SwipeStarting="listView_SwipeStarting">
 </syncfusion:SfListView>



private void listView_SwipeStarting(object sender, SwipeStartingEventArgs e)
{
   if (e.ItemIndex == 1)
       e.Cancel = true;
}

The following example demonstrates how to wire the swiping event in .


 <syncfusion:SfListView x:Name="listView"
                        ItemsSource="{Binding contactsinfo}"
                        AllowSwiping="True"
                        Swiping="listView_Swiping">
 </syncfusion:SfListView>



private void listView_Swiping(object sender, SwipingEventArgs e)
{
   if (e.OffSet > 70)
       e.Handled = true;
}

The following example demonstrates how to handle the SwipeEnded event in the .


 <syncfusion:SfListView x:Name="listView"
                        ItemsSource="{Binding contactsinfo}"
                        AllowSwiping="True"
                        SwipeEnded="listView_SwipeEnded">
 </syncfusion:SfListView>



private void listView_SwipeEnded(object sender, SwipeEndedEventArgs e)
{
   if (e.SwipeOffset > 70)
       listView.ResetSwipe();
}

